import{_ as t,o,c as r,a5 as a}from"./chunks/framework.C1VOsJ6A.js";const u=JSON.parse('{"title":"Account operator","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/account-operator.md","filePath":"reference/components/account-operator.md"}'),c={name:"reference/components/account-operator.md"};function n(s,e,i,p,d,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="account-operator" tabindex="-1">Account operator <a class="header-anchor" href="#account-operator" aria-label="Permalink to &quot;Account operator&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The account operator is the Platform Mesh component that converts defined account or organization entities into live control-plane structure. It owns reconciliation of the <code>Account</code>-Resource and ties its lifecycle to <strong>kcp</strong> workspace lifecycle. It ensures that each account gets the right isolation, workspace typing, and discoverable metadata.</p><p>Its role is to sit between the tenancy declared and how KCP exposes that tenancy without concerning itself with the implementation of identity or access management.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><p><strong>Account (<code>core.platform-mesh.io/v1alpha1</code>)</strong><code>Account</code> represents an entity in the workspace tree that can potentially hold other Accounts. <code>spec.type</code> currently only distinguishes an <strong>organization</strong> (type: <code>org</code>) from an <strong>account</strong> (type: <code>account</code>) but will possibly support other account types in the future. The spec carries display metadata, optional extensions, and structured <code>data</code>.</p><p><strong>AccountInfo (<code>core.platform-mesh.io/v1alpha1</code>)</strong> An <code>AccountInfo</code> resource with name <code>account</code> is created by the account operator in an account&#39;s workspace and holds information about the account the workspace belongs to. Its purpose is to expose that information to internal components that don&#39;t have information about or permission to workspaces/accounts higher up in the tree. It is comparable to the <code>LogicalCluster</code> object named <code>cluster</code> in every KCP workspace.</p><p>Together, these pieces implement the account model described in <a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a> and the resource-oriented view in <a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a>.</p><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kind</th><th>Link</th></tr></thead><tbody><tr><td>Source repository</td><td><a href="https://github.com/platform-mesh/account-operator" target="_blank" rel="noreferrer">platform-mesh/account-operator</a></td></tr><tr><td>Helm charts</td><td><a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a> — <code>charts/account-operator</code>, <code>charts/account-operator-crds</code></td></tr></tbody></table><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a></li><li><a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a></li><li><a href="./kcp.html">kcp</a></li></ul>',12)])])}const m=t(c,[["render",n]]);export{u as __pageData,m as default};
